import Stripe from 'stripe'

export const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-04-10',
})

import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

export function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(amount)
}

import { NextRequest, NextResponse } from 'next/server'
import { stripe } from '@/lib/stripe'

export async function POST(req: NextRequest) {
  try {
    const { amount } = await req.json()
    const paymentIntent = await stripe.paymentIntents.create({
      amount: Math.round(amount * 100),
      currency: 'usd',
      automatic_payment_methods: { enabled: true },
    })
    return NextResponse.json({ clientSecret: paymentIntent.client_secret })
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : 'Unknown error'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'

const PROMO_CODES: Record<string, number> = {
  SAVE10: 10,
  SAVE20: 20,
  WELCOME: 15,
}

export async function POST(req: NextRequest) {
  const { code } = await req.json()
  const discount = PROMO_CODES[code?.toUpperCase()]
  if (discount) {
    return NextResponse.json({ valid: true, discount, message: `$${discount} discount applied!` })
  }
  return NextResponse.json({ valid: false, discount: 0, message: 'Invalid promo code' })
}

import { NextRequest, NextResponse } from 'next/server'

export async function POST(req: NextRequest) {
  const { subtotal, state } = await req.json()
  const TAX_RATES: Record<string, number> = {
    CA: 0.0725, NY: 0.08, TX: 0.0625, FL: 0.06, WA: 0.065,
  }
  const rate = TAX_RATES[state?.toUpperCase()] ?? 0.05
  const tax = parseFloat((subtotal * rate).toFixed(2))
  return NextResponse.json({ tax, rate })
}

import { NextRequest, NextResponse } from 'next/server'
import { stripe } from '@/lib/stripe'

export async function POST(req: NextRequest) {
  try {
    const { paymentIntentId, orderData } = await req.json()
    const intent = await stripe.paymentIntents.retrieve(paymentIntentId)
    if (intent.status === 'succeeded') {
      const orderId = `ORD-${Date.now()}`
      console.log('Order confirmed:', orderId, orderData)
      return NextResponse.json({ success: true, orderId })
    }
    return NextResponse.json({ success: false, error: 'Payment not completed' }, { status: 400 })
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : 'Unknown error'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

'use client'
import { motion, AnimatePresence } from 'framer-motion'
import { CheckCircle, ChevronDown } from 'lucide-react'
import { cn } from '@/lib/utils'
import type { CheckoutStep } from '@/types/checkout'

type Props = {
  step: CheckoutStep
  stepNumber: number
  title: string
  isActive: boolean
  isCompleted: boolean
  summary?: string
  onEdit?: () => void
  children: React.ReactNode
}

export default function SectionAccordion({
  stepNumber, title, isActive, isCompleted, summary, onEdit, children
}: Props) {
  return (
    <div className={cn(
      'border rounded-xl overflow-hidden transition-all duration-200',
      isActive ? 'border-indigo-500 shadow-md' : 'border-gray-200',
      !isActive && !isCompleted && 'opacity-60'
    )}>
      <div className={cn(
        'flex items-center justify-between px-5 py-4',
        isActive ? 'bg-indigo-50' : isCompleted ? 'bg-white' : 'bg-gray-50'
      )}>
        <div className="flex items-center gap-3">
          <div className={cn(
            'w-7 h-7 rounded-full flex items-center justify-center text-sm font-bold',
            isCompleted ? 'bg-indigo-600 text-white' : isActive ? 'bg-indigo-600 text-white' : 'bg-gray-200 text-gray-500'
          )}>
            {isCompleted ? <CheckCircle className="w-4 h-4" /> : stepNumber}
          </div>
          <div>
            <p className="font-semibold text-gray-800">{title}</p>
            {isCompleted && summary && !isActive && (
              <p className="text-sm text-gray-500 mt-0.5">{summary}</p>
            )}
          </div>
        </div>
        {isCompleted && !isActive && onEdit && (
          <button onClick={onEdit} className="text-sm text-indigo-600 hover:underline font-medium">
            Edit
          </button>
        )}
        {!isCompleted && !isActive && (
          <ChevronDown className="w-4 h-4 text-gray-400" />
        )}
      </div>
      <AnimatePresence initial={false}>
        {isActive && (
          <motion.div
            key="content"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.25, ease: 'easeInOut' }}
          >
            <div className="px-5 py-5 bg-white border-t border-gray-100">
              {children}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

'use client'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { shippingSchema, type ShippingFormData } from '@/lib/validations/checkoutSchemas'
import { useCheckoutStore } from '@/store/checkoutStore'
import { cn } from '@/lib/utils'

const US_STATES = ['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY']

export default function ShippingSection() {
  const { setShipping, completeStep, shipping, subtotal, setTax } = useCheckoutStore()
  const { register, handleSubmit, watch, formState: { errors } } = useForm<ShippingFormData>({
    resolver: zodResolver(shippingSchema),
    defaultValues: shipping ?? { country: 'US' },
  })

  const onSubmit = async (data: ShippingFormData) => {
    setShipping(data)
    try {
      const res = await fetch('/api/checkout/calculate-tax', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ subtotal: subtotal(), state: data.state }),
      })
      const { tax } = await res.json()
      setTax(tax)
    } catch {}
    completeStep('shipping')
  }

  const field = (name: keyof ShippingFormData, label: string, placeholder: string, type = 'text', half = false) => (
    <div className={half ? 'flex-1' : 'w-full'}>
      <label className="block text-sm font-medium text-gray-700 mb-1">{label}</label>
      <input
        {...register(name)}
        type={type}
        placeholder={placeholder}
        className={cn(
          'w-full border rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500',
          errors[name] ? 'border-red-400' : 'border-gray-300'
        )}
      />
      {errors[name] && <p className="text-red-500 text-xs mt-1">{errors[name]?.message}</p>}
    </div>
  )

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
      <div className="flex gap-3">
        {field('firstName', 'First name *', 'Jane', 'text', true)}
        {field('lastName', 'Last name *', 'Doe', 'text', true)}
      </div>
      {field('address1', 'Address *', '123 Main St')}
      {field('address2', 'Apartment, suite, etc.', 'Apt 4B')}
      <div className="flex gap-3">
        {field('city', 'City *', 'New York', 'text', true)}
        <div className="flex-1">
          <label className="block text-sm font-medium text-gray-700 mb-1">State *</label>
          <select
            {...register('state')}
            className={cn(
              'w-full border rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500',
              errors.state ? 'border-red-400' : 'border-gray-300'
            )}
          >
            <option value="">Select</option>
            {US_STATES.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
          {errors.state && <p className="text-red-500 text-xs mt-1">{errors.state.message}</p>}
        </div>
      </div>
      <div className="flex gap-3">
        {field('zip', 'ZIP code *', '10001', 'text', true)}
        <div className="flex-1">
          <label className="block text-sm font-medium text-gray-700 mb-1">Country *</label>
          <select
            {...register('country')}
            className="w-full border border-gray-300 rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
          >
            <option value="US">United States</option>
            <option value="CA">Canada</option>
            <option value="GB">United Kingdom</option>
          </select>
        </div>
      </div>
      <button type="submit" className="w-full bg-indigo-600 text-white py-2.5 rounded-lg font-semibold hover:bg-indigo-700 transition">
        Continue to Delivery
      </button>
    </form>
  )
}

'use client'
import { useState } from 'react'
import { useCheckoutStore } from '@/store/checkoutStore'
import { formatCurrency } from '@/lib/utils'
import type { DeliveryOption } from '@/types/checkout'

export default function DeliverySection() {
  const { deliveryOptions, delivery, setDelivery, completeStep } = useCheckoutStore()
  const [selected, setSelected] = useState<string>(delivery?.id ?? '')

  const handleContinue = () => {
    const option = deliveryOptions.find(o => o.id === selected)
    if (!option) return
    setDelivery(option)
    completeStep('delivery')
  }

  return (
    <div className="space-y-3">
      {deliveryOptions.map((opt: DeliveryOption) => (
        <label
          key={opt.id}
          className={`flex items-center justify-between p-4 border rounded-xl cursor-pointer transition ${
            selected === opt.id ? 'border-indigo-500 bg-indigo-50' : 'border-gray-200 hover:border-gray-300'
          }`}
        >
          <div className="flex items-center gap-3">
            <input
              type="radio"
              name="delivery"
              value={opt.id}
              checked={selected === opt.id}
              onChange={() => setSelected(opt.id)}
              className="accent-indigo-600"
            />
            <div>
              <p className="font-medium text-sm">{opt.label}</p>
              <p className="text-xs text-gray-500">{opt.description}</p>
            </div>
          </div>
          <span className="font-semibold text-sm">{opt.price === 0 ? 'Free' : formatCurrency(opt.price)}</span>
        </label>
      ))}
      <button
        onClick={handleContinue}
        disabled={!selected}
        className="w-full bg-indigo-600 text-white py-2.5 rounded-lg font-semibold hover:bg-indigo-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
      >
        Continue to Payment
      </button>
    </div>
  )
}

'use client'
import { useState, useEffect } from 'react'
import { loadStripe } from '@stripe/stripe-js'
import { Elements, CardElement, useStripe, useElements } from '@stripe/react-stripe-js'
import { useCheckoutStore } from '@/store/checkoutStore'
import { formatCurrency } from '@/lib/utils'

const stripePromise = loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY!)

function CardForm() {
  const stripe = useStripe()
  const elements = useElements()
  const { clientSecret, total, completeStep, setOrderComplete, contact, shipping, delivery } = useCheckoutStore()
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!stripe || !elements || !clientSecret) return
    setLoading(true)
    setError(null)
    const card = elements.getElement(CardElement)
    if (!card) return
    const { error: stripeError, paymentIntent } = await stripe.confirmCardPayment(clientSecret, {
      payment_method: {
        card,
        billing_details: {
          name: `${shipping?.firstName} ${shipping?.lastName}`,
          email: contact?.email,
        },
      },
    })
    if (stripeError) {
      setError(stripeError.message ?? 'Payment failed')
      setLoading(false)
      return
    }
    if (paymentIntent?.status === 'succeeded') {
      setOrderComplete()
      completeStep('payment')
    }
    setLoading(false)
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="border border-gray-300 rounded-lg px-3 py-3">
        <CardElement options={{ style: { base: { fontSize: '14px', color: '#374151' } } }} />
      </div>
      {error && <p className="text-red-500 text-sm">{error}</p>}
      <p className="text-xs text-gray-500">🔒 Your payment info is encrypted and secure via Stripe.</p>
      <button
        type="submit"
        disabled={!stripe || loading}
        className="w-full bg-indigo-600 text-white py-2.5 rounded-lg font-semibold hover:bg-indigo-700 transition disabled:opacity-60"
      >
        {loading ? 'Processing...' : `Pay ${formatCurrency(total())}`}
      </button>
    </form>
  )
}

export default function PaymentSection() {
  const { total, setClientSecret, clientSecret } = useCheckoutStore()
  const [ready, setReady] = useState(false)

  useEffect(() => {
    fetch('/api/checkout/create-intent', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ amount: total() }),
    })
      .then(r => r.json())
      .then(({ clientSecret }) => {
        if (clientSecret) { setClientSecret(clientSecret); setReady(true) }
      })
      .catch(() => setReady(true))
  }, [])

  if (!ready) return <div className="animate-pulse h-20 bg-gray-100 rounded-lg" />

  return (
    <Elements stripe={stripePromise} options={{ clientSecret: clientSecret ?? undefined }}>
      <CardForm />
    </Elements>
  )
}

'use client'
import { useState } from 'react'
import { useCheckoutStore } from '@/store/checkoutStore'

export default function PromoCodeInput() {
  const { setPromo, promoCode } = useCheckoutStore()
  const [code, setCode] = useState(promoCode)
  const [message, setMessage] = useState('')
  const [valid, setValid] = useState<boolean | null>(null)
  const [loading, setLoading] = useState(false)

  const apply = async () => {
    if (!code.trim()) return
    setLoading(true)
    const res = await fetch('/api/checkout/validate-promo', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ code }),
    })
    const data = await res.json()
    setValid(data.valid)
    setMessage(data.message)
    if (data.valid) setPromo(code, data.discount)
    setLoading(false)
  }

  return (
    <div>
      <label className="block text-xs font-medium text-gray-500 mb-1.5">Promo Code</label>
      <div className="flex gap-2">
        <input
          value={code}
          onChange={e => { setCode(e.target.value); setValid(null); setMessage('') }}
          placeholder="Enter code"
          className="flex-1 border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
        />
        <button
          onClick={apply}
          disabled={loading}
          className="bg-gray-800 text-white px-3 py-2 rounded-lg text-sm font-medium hover:bg-gray-700 transition disabled:opacity-50"
        >
          {loading ? '...' : 'Apply'}
        </button>
      </div>
      {message && (
        <p className={`text-xs mt-1.5 ${valid ? 'text-green-600' : 'text-red-500'}`}>{message}</p>
      )}
    </div>
  )
}

'use client'
import { useCheckoutStore, STEPS } from '@/store/checkoutStore'
import SectionAccordion from './SectionAccordion'
import ContactSection from './sections/ContactSection'
import ShippingSection from './sections/ShippingSection'
import DeliverySection from './sections/DeliverySection'
import PaymentSection from './sections/PaymentSection'
import ReviewSection from './sections/ReviewSection'
import OrderSummary from './OrderSummary'
import type { CheckoutStep } from '@/types/checkout'

const SECTION_META: Record<CheckoutStep, { title: string; stepNumber: number }> = {
  contact: { title: 'Contact Information', stepNumber: 1 },
  shipping: { title: 'Shipping Address', stepNumber: 2 },
  delivery: { title: 'Delivery Method', stepNumber: 3 },
  payment: { title: 'Payment', stepNumber: 4 },
  review: { title: 'Review & Confirm', stepNumber: 5 },
}

const SECTION_COMPONENTS: Record<CheckoutStep, React.ReactNode> = {
  contact: <ContactSection />,
  shipping: <ShippingSection />,
  delivery: <DeliverySection />,
  payment: <PaymentSection />,
  review: <ReviewSection />,
}

function getSummary(step: CheckoutStep, store: ReturnType<typeof useCheckoutStore>): string {
  if (step === 'contact') return store.contact?.email ?? ''
  if (step === 'shipping') return store.shipping ? `${store.shipping.address1}, ${store.shipping.city}` : ''
  if (step === 'delivery') return store.delivery?.label ?? ''
  if (step === 'payment') return 'Card ending in ****'
  return ''
}

export default function CheckoutShell() {
  const store = useCheckoutStore()
  const { activeStep, completedSteps, setActiveStep, orderComplete } = store

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white border-b border-gray-200 px-4 py-4">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <span className="text-xl font-bold text-indigo-600">ShopCo</span>
          <span className="text-sm text-gray-500">Secure Checkout 🔒</span>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8">
        <div className="flex flex-col lg:flex-row gap-8">
          {/* Left: Steps */}
          <div className="flex-1 space-y-3">
            {orderComplete ? (
              <div className="bg-white border border-green-200 rounded-xl p-8 text-center">
                <div className="text-5xl mb-4">🎉</div>
                <h2 className="text-2xl font-bold text-gray-800">Thank you for your order!</h2>
                <p className="text-gray-500 mt-2">A confirmation has been sent to {store.contact?.email}</p>
              </div>
            ) : (
              STEPS.map((step) => (
                <SectionAccordion
                  key={step}
                  step={step}
                  stepNumber={SECTION_META[step].stepNumber}
                  title={SECTION_META[step].title}
                  isActive={activeStep === step}
                  isCompleted={completedSteps.has(step)}
                  summary={getSummary(step, store)}
                  onEdit={() => setActiveStep(step)}
                >
                  {SECTION_COMPONENTS[step]}
                </SectionAccordion>
              ))
            )}
          </div>

          {/* Right: Order Summary */}
          <div className="lg:w-80 xl:w-96">
            <div className="lg:sticky lg:top-6">
              <OrderSummary />
            </div>
          </div>
        </div>
      </main>
    </div>
  )
}

import CheckoutShell from '@/components/checkout/CheckoutShell'

export default function CheckoutPage() {
  return <CheckoutShell />
}

export default function CheckoutLayout({ children }: { children: React.ReactNode }) {
  return <>{children}</>
}

